@page "/category/{CategoryName}"
@using RecipeCommunity.Models

<PageTitle>@CategoryName Recipes - Recipe Community</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">@CategoryName</li>
    </ol>
</nav>

@if (category is not null)
{
    <div class="mb-4">
        <h1><span class="me-2">@category.Icon</span>@category.Name Recipes</h1>
        <p class="lead text-muted">@category.Description</p>
    </div>

    <div class="row row-cols-1 row-cols-md-2 g-4">
        @foreach (var recipe in recipes)
        {
            <div class="col">
                <div class="card h-100 shadow-sm">
                    <div class="card-body">
                        <h4 class="card-title">@recipe.Title</h4>
                        <p class="card-text">@recipe.Description</p>
                        <div class="d-flex justify-content-between align-items-center">
                            <span class="text-warning">
                                @for (int i = 1; i <= 5; i++)
                                {
                                    @(i <= (int)Math.Round(recipe.AverageRating) ? "★" : "☆")
                                }
                                <small class="text-muted ms-1">(@recipe.RatingCount)</small>
                            </span>
                            <a href="@($"recipe/{recipe.Id}")" class="btn btn-outline-primary btn-sm">View Recipe</a>
                        </div>
                    </div>
                </div>
            </div>
        }
    </div>
}
else
{
    <div class="alert alert-warning">Category not found.</div>
}

@code {
    [Parameter]
    public string CategoryName { get; set; } = string.Empty;

    private RecipeCategory? category;
    private List<Recipe> recipes = [];

    protected override void OnParametersSet()
    {
        category = SampleData.Categories
            .FirstOrDefault(c => c.Name.Equals(CategoryName, StringComparison.OrdinalIgnoreCase));
        recipes = SampleData.Recipes
            .Where(r => r.Category.Equals(CategoryName, StringComparison.OrdinalIgnoreCase))
            .ToList();
    }
}

@page "/recipe/{RecipeId:int}"
@using RecipeCommunity.Models
@using RecipeCommunity.Client.Components

<PageTitle>@(recipe?.Title ?? "Recipe") - Recipe Community</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item"><a href="@($"category/{recipe?.Category.ToLower()}")">@recipe?.Category</a></li>
        <li class="breadcrumb-item active">@recipe?.Title</li>
    </ol>
</nav>

@if (recipe is not null)
{
    <div class="row">
        <div class="col-lg-8">
            <h1>@recipe.Title</h1>
            <p class="lead text-muted">@recipe.Description</p>

            <div class="mb-4">
                <h3>Ingredients</h3>
                <ul class="list-group list-group-flush">
                    @foreach (var ingredient in recipe.Ingredients)
                    {
                        <li class="list-group-item">@ingredient</li>
                    }
                </ul>
            </div>

            <div class="mb-4">
                <h3>Steps</h3>
                <ol class="list-group list-group-numbered list-group-flush">
                    @foreach (var step in recipe.Steps)
                    {
                        <li class="list-group-item">@step</li>
                    }
                </ol>
            </div>
        </div>

        <div class="col-lg-4">
            <div class="card shadow-sm">
                <div class="card-body text-center">
                    <h5 class="card-title">Rate this Recipe</h5>
                    <p class="text-muted small">Average: @recipe.AverageRating.ToString("F1") / 5 (@recipe.RatingCount ratings)</p>
                    <StarRating @rendermode="InteractiveWebAssembly" RecipeId="recipe.Id" />
                </div>
            </div>
        </div>
    </div>
}
else
{
    <div class="alert alert-warning">Recipe not found.</div>
}

@code {
    [Parameter]
    public int RecipeId { get; set; }

    private Recipe? recipe;

    protected override void OnParametersSet()
    {
        recipe = SampleData.Recipes.FirstOrDefault(r => r.Id == RecipeId);
    }
}

@namespace RecipeCommunity.Client.Components
@rendermode InteractiveWebAssembly

<div class="star-rating">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= (userRating ?? hoverRating) ? "filled" : "")"
              @onclick="() => Rate(star)"
              @onmouseover="() => hoverRating = star"
              @onmouseout="() => hoverRating = 0"
              role="button"
              title="@($"Rate {star} star{(star > 1 ? "s" : "")}")">
            @(star <= (userRating ?? hoverRating) ? "★" : "☆")
        </span>
    }
    @if (userRating.HasValue)
    {
        <div class="mt-2">
            <small class="text-success">You rated this @userRating stars! Thank you!</small>
        </div>
    }
</div>

<style>
    .star-rating .star {
        font-size: 2rem;
        cursor: pointer;
        color: #ffc107;
        transition: transform 0.1s;
    }
    .star-rating .star:hover {
        transform: scale(1.2);
    }
    .star-rating .star.filled {
        color: #ffc107;
    }
</style>

@code {
    [Parameter]
    public int RecipeId { get; set; }

    private int? userRating;
    private int hoverRating;

    private void Rate(int rating)
    {
        userRating = rating;
    }
}

@page "/submit"
@rendermode InteractiveWebAssembly

<PageTitle>Submit a Recipe - Recipe Community</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">Submit Recipe</li>
    </ol>
</nav>

<h1>Submit a Recipe</h1>
<p class="lead text-muted">Share your favorite recipe with the community!</p>

@if (submitted)
{
    <div class="alert alert-success">
        <h4>🎉 Recipe Submitted!</h4>
        <p>Thank you for sharing "<strong>@model.Title</strong>" with the community. Your recipe will be reviewed and published soon.</p>
        <button class="btn btn-primary" @onclick="Reset">Submit Another</button>
    </div>
}
else
{
    <div class="row">
        <div class="col-lg-8">
            <EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="recipeForm">
                <DataAnnotationsValidator />
                <ValidationSummary class="text-danger" />

                <div class="mb-3">
                    <label for="title" class="form-label">Recipe Title</label>
                    <InputText id="title" @bind-Value="model.Title" class="form-control" placeholder="e.g., Grandma's Apple Pie" />
                    <ValidationMessage For="() => model.Title" class="text-danger" />
                </div>

                <div class="mb-3">
                    <label for="category" class="form-label">Category</label>
                    <InputSelect id="category" @bind-Value="model.Category" class="form-select">
                        <option value="">-- Select a category --</option>
                        <option value="Breakfast">Breakfast</option>
                        <option value="Lunch">Lunch</option>
                        <option value="Dinner">Dinner</option>
                        <option value="Desserts">Desserts</option>
                        <option value="Snacks">Snacks</option>
                    </InputSelect>
                    <ValidationMessage For="() => model.Category" class="text-danger" />
                </div>

                <div class="mb-3">
                    <label for="ingredients" class="form-label">Ingredients</label>
                    <InputTextArea id="ingredients" @bind-Value="model.Ingredients" class="form-control" rows="5"
                        placeholder="Enter each ingredient on a new line" />
                    <ValidationMessage For="() => model.Ingredients" class="text-danger" />
                    <small class="form-text text-muted">Enter each ingredient on a separate line.</small>
                </div>

                <div class="mb-3">
                    <label for="steps" class="form-label">Steps</label>
                    <InputTextArea id="steps" @bind-Value="model.Steps" class="form-control" rows="6"
                        placeholder="Enter each step on a new line" />
                    <ValidationMessage For="() => model.Steps" class="text-danger" />
                    <small class="form-text text-muted">Enter each step on a separate line.</small>
                </div>

                <button type="submit" class="btn btn-success btn-lg">Submit Recipe</button>
            </EditForm>
        </div>
    </div>
}

@code {
    private RecipeFormModel model = new();
    private bool submitted;

    private void HandleSubmit()
    {
        submitted = true;
    }

    private void Reset()
    {
        model = new();
        submitted = false;
    }

    private class RecipeFormModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please enter a recipe title.")]
        [System.ComponentModel.DataAnnotations.StringLength(100, MinimumLength = 3, ErrorMessage = "Title must be between 3 and 100 characters.")]
        public string Title { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please select a category.")]
        public string Category { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please enter at least one ingredient.")]
        public string Ingredients { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please enter at least one step.")]
        public string Steps { get; set; } = string.Empty;
    }
}

